parameters.jsCode:
const exp = $input.first().json;
const p = exp.prospecto;

// Construir el Payload JSON Final según especificación del .md
const payloadFinal = {
  prospecto_identificacion: {
    origen_canal: p.origenCanal || 'Meta Ads',
    nombre_completo: p.nombreCompleto,
    telefono_contacto: p.telefonoContacto,
    curp_validada_regex: p.curp,
    nss_validado_regex: p.nss
  },
  analisis_financiero_ia: {
    monto_pension_actual: exp.montoPensionActual,
    institucion_bancaria: exp.institucionBancaria,
    cuenta_clabe_validada: exp.cuentaClabe
  },
  control_operativo: {
    estatus_actual_hoja: 'VIABLE',
    fecha_despacho: new Date().toISOString()
  },
  expediente_empaquetado: {
    nombre_carpeta_drive: exp.nombreCarpetaDrive,
    url_directa_carpeta: exp.urlCarpetaDrive,
    auditoria_ocr_documentos: {
      ine_digital_ambos_lados: exp.ineAmbosLados === 'APROBADO' ? 'Aprobado' : 'Pendiente',
      comprobante_cfe_digital: exp.comprobanteDomicilio === 'APROBADO' ? 'Aprobado' : 'Pendiente',
      resolucion_pension_digital: exp.resolucionPension === 'APROBADO' ? 'Aprobado' : 'Pendiente',
      estados_cuenta_movimientos: exp.estadosCuenta === 'APROBADO' ? 'Aprobado' : 'Pendiente',
      foto_con_ine_mandatoria: exp.fotoConIne === 'APROBADO' ? 'Aprobado' : 'Pendiente'
    }
  },
  formalizacion_legal: {
    evidencia_tipo: exp.evidenciaTipo || 'Videoconvenio',
    aprobacion_superior_manual: exp.aprobacionSuperior || false,
    aprobado_por: exp.aprobadoPor
  }
};

return [{ json: { payload: payloadFinal, telefono_prospecto: p.telefonoContacto } }];

